import org.wordpress.android.fluxc.Dispatcher
import org.wordpress.android.fluxc.model.SiteModel
import org.wordpress.android.fluxc.store.PageStore
import org.wordpress.android.fluxc.store.PostStore
import org.wordpress.android.fluxc.store.SiteStore
import org.wordpress.android.util.NetworkUtilsWrapper
import org.wordpress.android.util.analytics.AnalyticsTrackerWrapper
import org.wordpress.android.viewmodel.helpers.ConnectionStatus

@ExperimentalCoroutinesApi
@RunWith(MockitoJUnitRunner::class)
class UploadStarterMutexTest : BaseUnitTest() {

    private val context: Context = mock()
    private val dispatcher: Dispatcher = mock()
    private val postStore: PostStore = mock()
    private val pageStore: PageStore = mock()
    private val siteStore: SiteStore = mock()
    private val uploadActionUseCase: UploadActionUseCase = mock()
    private val tracker: AnalyticsTrackerWrapper = mock()
    private val uploadServiceFacade: UploadServiceFacade = mock()
    private val networkUtilsWrapper: NetworkUtilsWrapper = mock()
    private val connectionStatus: LiveData<ConnectionStatus> = mock()

    private lateinit var uploadStarter: UploadStarter

    @Test(expected = IllegalStateException::class)
    fun `queueUploadFromSite throws IllegalStateException when CancellationException occurs during upload`() = runTest(testDispatcher()) {
        uploadStarter = UploadStarter(
            context,
            dispatcher,
            postStore,
            pageStore,
            siteStore,
            uploadActionUseCase,
            tracker,
            testDispatcher(), // bgDispatcher
            testDispatcher(), // ioDispatcher
            uploadServiceFacade,
            networkUtilsWrapper,
            connectionStatus
        )

        whenever(networkUtilsWrapper.isNetworkAvailable()).thenReturn(true)
        val site = SiteModel()

        // Make postStore throw CancellationException to trigger the catch block in upload()
        whenever(postStore.getPostsWithLocalChanges(any())).thenThrow(CancellationException("Simulated cancellation"))

        // This should throw IllegalStateException because of the double unlock
        uploadStarter.queueUploadFromSite(site).join()
    }
}
